const amount = Number((context.panel.elements.find(function(e){return e.id==='custom_amount';})||{}).value || 0);
if (amount <= 0) {
  context.grafana.notifyWarning(['Invalid amount', 'Enter a positive credit amount before clicking.']);
  return;
}
if (!window.confirm('Add ' + amount.toLocaleString() + ' credits to ${matrix_user_id}?')) { return; }
const params = new URLSearchParams({ user: '${matrix_user_id}', credit: String(amount) });
try {
  const r = await fetch('${realm_server}_grafana-add-credit?' + params.toString(), { method: 'POST', headers: { 'Authorization': 'Bearer ${grafana_secret}' } });
  if (r.ok) {
    context.grafana.notifySuccess(['Credit added', '+' + amount.toLocaleString() + ' credits to ${matrix_user_id}']);
    if (typeof context.grafana.refresh === 'function') { context.grafana.refresh(); }
  } else {
    const txt = await r.text();
    context.grafana.notifyError(['Add credit failed', 'HTTP ' + r.status + ': ' + txt]);
  }
} catch (err) {
  context.grafana.notifyError(['Add credit failed', String(err)]);
}
